--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelHelpPicture:OnModelInit()
    self._recordRefIdList = {}
    self:ParseConfig()

    self:ModelNetMsgRecv(LProtoIds.HelpPictureInfoResp,function (...) self:OnHelpPictureInfoResp(...) end)
    self:ModelNetMsgRecv(LProtoIds.PubSupOperaResp,function (...) self:OnPubSupOperaResp(...) end)
    self:ModelEventRecv(EventNames.ON_WND_FINISH,function (...) self:OnWndOpen(...) end)
end

--在协议数据处理完之后需要调用finish
function ModelHelpPicture:OnModelRequest()
    self:PubSupOperaReq(1)

    self:ModelFinish()
end

-----------------------------------------------------
---req
function ModelHelpPicture:PubSupOperaReq(reqType, refId)
    local pb = LProtoHelper.CreateProto(LProtoIds.PubSupOperaReq)
    pb.type = reqType  -- 1：请求图文指引数据  2：完成图文指引
    pb.args = tostring(refId) or "0"   -- 完成图文指引的refId

    SendMessage(pb,LProtoIds.PubSupOperaReq)
end

--------------------------------------------------------
---resp
function ModelHelpPicture:OnHelpPictureInfoResp(pb)
    local info = StructHelpPictureInfo:New()
    info:CreateByPb(pb.info)
    local refId = info.refId

    for k,v in ipairs(refId) do
        self._recordRefIdList[v] = true
    end
end

function ModelHelpPicture:OnPubSupOperaResp(pb)
    if pb.type == 1 then
        --请求的图文指引数据
    elseif pb.type == 2 then
        --请求完成图文指引
    end
end

-----------------------------------------------------------------------------------------------------------------------
----ConfigRef
function ModelHelpPicture:ParseConfig()
    self._prefabDataList = {}
    for k,v in pairs(GameTable.SupportPrefabRef) do
        self._prefabDataList[v.wndName] = v.refId
    end
end


function ModelHelpPicture:GetHelpPrefabRefByRefId(refId)
    local ref = GameTable.SupportPrefabRef[refId]
    if not ref then
        printInfoNR2("配置缺失", string.format("GameTable.SupportPrefabRef[%s]",refId ))
    end

    return ref
end


function ModelHelpPicture:GetHelpPictureRefListByGroup(groupId)
    local refList = {}
    for k,v in pairs(GameTable.SupportPictureRef) do
        if v.group == groupId then
            table.insert(refList, v)
        end
    end

    if table.isempty(refList) then
        printInfoNR2("配置缺失", string.format("GameTable.SupportPrefabRef, group = %s", groupId))
    else
        table.sort(refList, function(a, b)
            local sortA = a.sort
            local sortB = b.sort
            if sortA < 0 or sortB < 0 then
                return sortB < 0
            end

            return sortA < sortB
        end)
    end

    return refList
end

function ModelHelpPicture:GetHelpPrefabRefIdByWndName(wndName)
    if not self._prefabDataList then
        return
    end
    local refId = self._prefabDataList[wndName]
    return refId
end

-----------------------------------------------------------------------------------------------------------------------
----
function ModelHelpPicture:CheckShowHelpPrefabByWndName(wndName)
    if not self:IsOpenRegion() then
        return false
    end

    if wndName == "UIBzPicturePop" then
        return false
    end

    local refId = self:GetHelpPrefabRefIdByWndName(wndName)
    if not refId then
        return false
    end

    if self._recordRefIdList[refId] then
        return false
    end

    return true
end


function ModelHelpPicture:OnWndOpen(wndName)
    if not self:IsOpenRegion() then
        return
    end

    if not self:CheckShowHelpPrefabByWndName(wndName) then
        return
    end

    GF.OpenWnd("UIBzPicturePop",{targetWndName = wndName})
end

function ModelHelpPicture:IsOpenRegion()
    return gLGameLanguage:IsJapanRegion()
end


return ModelHelpPicture